#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std; 
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &x){if(x>9)print(x/10);putchar(x%10+'0');}
const int N=5e5+10,M=1e5+10;
bool f1;
int head[N<<3],nxt[N<<5],des[N<<5];
bool val[N<<5],inq[N<<3],vis[N<<3];int cgt,n,m,s;
int i1[N<<2],i2[N<<2],cnt,i3[M<<1],dis[N<<3];
bool f2;
inline void ins(int x,int y,bool z){nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;}
inline void build1(int l=1,int r=n,int cur=1)
{
	i1[cur]=++cnt;if(l==r){ins(l,i1[cur],1);return;}
	int mid=(l+r)>>1;build1(l,mid,cur<<1);build1(mid+1,r,cur<<1|1);
	ins(i1[cur<<1],i1[cur],0);ins(i1[cur<<1|1],i1[cur],0);
}
inline void build2(int l=1,int r=n,int cur=1)
{
	i2[cur]=++cnt;if(l==r){ins(i2[cur],l,0);return;}
	int mid=(l+r)>>1;build2(l,mid,cur<<1);build2(mid+1,r,cur<<1|1);
	ins(i2[cur],i2[cur<<1],0);ins(i2[cur],i2[cur<<1|1],0);
}
inline void add1(int ql,int qr,int x,int l=1,int r=n,int cur=1)
{
	if(ql<=l&&r<=qr){ins(i1[cur],x,0);return;}int mid=(l+r)>>1;
	if(ql<=mid)add1(ql,qr,x,l,mid,cur<<1);if(qr>mid)add1(ql,qr,x,mid+1,r,cur<<1|1);
}
inline void add2(int ql,int qr,int x,int l=1,int r=n,int cur=1)
{
	if(ql<=l&&r<=qr){ins(x,i2[cur],0);return;}int mid=(l+r)>>1;
	if(ql<=mid)add2(ql,qr,x,l,mid,cur<<1);if(qr>mid)add2(ql,qr,x,mid+1,r,cur<<1|1);
}
deque<int> q;inline void dij()
{
	memset(dis,0x3f,sizeof(dis));
	dis[s]=0;q.push_back(s);
	while(!q.empty())
	{
		int u=q.front();q.pop_front();if(vis[u])continue;
		for(int i=head[u];i;i=nxt[i])
		{
			int v=des[i];
			if(dis[v]>dis[u]+val[i])
			{
				dis[v]=dis[u]+val[i];
				if(val[i])q.push_back(v);
				else q.push_front(v);
			}
		}
	}
}
int main()
{
//	freopen("journeys.in","r",stdin);
//	freopen("journeys.out","w",stdout);
	cnt=n=read();m=read();s=read();build1();build2();	
	rep(1,m,i)
	{
		int a=read(),b=read(),c=read(),d=read();
		i3[i<<1]=++cnt;i3[i<<1|1]=++cnt;
		add1(a,b,i3[i<<1]);add1(c,d,i3[i<<1|1]);
		add2(c,d,i3[i<<1]);add2(a,b,i3[i<<1|1]);
	}
	dij();rep(1,n,i)print(dis[i]),putchar('\n');return 0;
}
